def extract_codes(cpc_str):
    if not cpc_str:
        return []
    try:
        arr = json.loads(cpc_str)
        codes = []
        for e in arr if isinstance(arr, list) else []:
            code = e.get('code') if isinstance(e, dict) else None
            if code:
                code = code.strip()
                grp = code.split('/')[0]
                if grp in level5_set:
                    codes.append(grp)
